const authHeader = $('Webhook').first().json.headers.authorization;

if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return [{
        json: {
            error: 'missing_token',
            error_description: 'Authorization header missing or invalid'
        },
        http: { statusCode: 401 }
    }];
}

const token = authHeader.substring(7); // Entferne "Bearer "

// Token-Format prüfen (JWT: header.payload.signature)
const tokenParts = token.split('.');
if (tokenParts.length !== 3) {
    return [{
        json: {
            error: 'invalid_token',
            error_description: 'Token format invalid'
        },
        http: { statusCode: 401 }
    }];
}

return [{
    json: {
        access_token: token,
        header: tokenParts[0],
        payload: tokenParts[1],
        signature: tokenParts[2]
    }
}];

const crypto = require('crypto');

const tokenData = $('Parse Authorization Header').first().json;
const jwtSecret = $env.JWT_SECRET;

try {
    // Signature validieren
    const signatureInput = `${tokenData.header}.${tokenData.payload}`;
    const expectedSignature = crypto
        .createHmac('sha256', jwtSecret)
        .update(signatureInput)
        .digest('base64url');

    if (expectedSignature !== tokenData.signature) {
        return [{
            json: {
                error: 'invalid_token',
                error_description: 'Token signature invalid'
            },
            http: { statusCode: 401 }
        }];
    }

    // Payload dekodieren
    const payload = JSON.parse(Buffer.from(tokenData.payload, 'base64url').toString());

    // Expiration prüfen
    const now = Math.floor(Date.now() / 1000);
    if (payload.exp < now) {
        return [{
            json: {
                error: 'token_expired',
                error_description: 'Token has expired'
            },
            http: { statusCode: 401 }
        }];
    }

    // Audience prüfen
    if (payload.aud !== $env.OAUTH_AUDIENCE) {
        return [{
            json: {
                error: 'invalid_audience',
                error_description: 'Token audience mismatch'
            },
            http: { statusCode: 401 }
        }];
    }

    return [{
        json: {
            valid: true,
            client_id: payload.client_id,
            scopes: payload.scope.split(' '),
            expires_at: payload.exp,
            token_id: payload.jti
        }
    }];

} catch (error) {
    return [{
        json: {
            error: 'invalid_token',
            error_description: 'Token validation failed'
        },
        http: { statusCode: 401 }
    }];
}
